CREATE TABLE `upgrade_groups` (`id` int AUTO_INCREMENT NOT NULL, `projectId` int NOT NULL, `category` varchar(128) NOT NULL, `position` int NOT NULL DEFAULT 0, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `upgrade_groups_id` PRIMARY KEY(`id`));
CREATE TABLE `upgrade_options` (`id` int AUTO_INCREMENT NOT NULL, `groupId` int NOT NULL, `projectId` int NOT NULL, `optionName` varchar(256) NOT NULL, `description` text, `imageUrl` text, `isIncluded` boolean NOT NULL DEFAULT false, `priceDelta` decimal(10,2) DEFAULT '0', `position` int NOT NULL DEFAULT 0, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `upgrade_options_id` PRIMARY KEY(`id`));
CREATE TABLE `upgrade_selections` (`id` int AUTO_INCREMENT NOT NULL, `projectId` int NOT NULL, `clientToken` varchar(128) NOT NULL, `upgradeOptionId` int NOT NULL, `selected` boolean NOT NULL DEFAULT false, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `upgrade_selections_id` PRIMARY KEY(`id`));
CREATE TABLE `upgrade_submissions` (`id` int AUTO_INCREMENT NOT NULL, `projectId` int NOT NULL, `clientToken` varchar(128) NOT NULL, `totalUpgradeCost` decimal(12,2), `submittedAt` timestamp NOT NULL DEFAULT (now()), `lockedAt` timestamp NULL, `notes` text, CONSTRAINT `upgrade_submissions_id` PRIMARY KEY(`id`))

